import React from 'react';
import { Link } from 'react-router-dom';

const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, handleLogout }) => {

    const navigateTo = (menuId) => {
        // Cek apakah function ada sebelum dipanggil agar tidak error
        if (setActiveMenu) {
            setActiveMenu(menuId);
        }
    };

    return (
        <nav style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '20px 80px', background: '#0c0a09', borderBottom: '1px solid #262626' }}>
            <div onClick={() => navigateTo('eksplorasi')} style={{ cursor: 'pointer' }}>
                <h1 style={{ color: '#ea580c', margin: 0, fontSize: '24px' }}>PasukanYerusSolo</h1>
            </div>

            <div style={{ display: 'flex', gap: '24px', alignItems: 'center' }}>
                <Link to="/" style={{ color: '#fef3c7', textDecoration: 'none', fontWeight: 'bold' }}>Home</Link>

                <button 
                    onClick={() => navigateTo('eksplorasi')}
                    style={{ background: 'none', border: 'none', color: activeMenu === 'eksplorasi' ? '#f59e0b' : '#fff', fontWeight: '700', cursor: 'pointer' }}
                >
                    Eksplorasi
                </button>

                {isAuthenticated ? (
                    <>
                        <button onClick={() => navigateTo('favorit')} style={{ background: 'none', border: 'none', color: activeMenu === 'favorit' ? '#f59e0b' : '#fff', fontWeight: '700', cursor: 'pointer' }}>Favorit</button>
                        <button onClick={() => navigateTo('status')} style={{ background: 'none', border: 'none', color: activeMenu === 'status' ? '#f59e0b' : '#fff', fontWeight: '700', cursor: 'pointer' }}>Status</button>
                        <button onClick={handleLogout} style={{ padding: '8px 20px', borderRadius: '20px', border: '1px solid #ef4444', background: 'transparent', color: '#ef4444', fontWeight: '700', cursor: 'pointer' }}>Keluar</button>
                    </>
                ) : (
                    <>
                        <Link to="/" style={{ color: '#fef3c7', textDecoration: 'none', fontWeight: 'bold' }}>Home</Link>
                        <button 
                            onClick={() => window.location.href = '/login'}
                            style={{ padding: '8px 20px', borderRadius: '20px', border: '1px solid #ea580c', background: 'transparent', color: '#ea580c', fontWeight: '700', cursor: 'pointer' }}
                        >
                            Login
                        </button>
                    </>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
